// src/services/multiWindowQuestService.ts
import { db } from '../db';
import { DateTime } from 'luxon';
const WINDOWS = { morning: [6, 12], afternoon: [12, 18], evening: [18, 24] };
function currentWindow(timezone: string): keyof typeof WINDOWS | null {
  const h = DateTime.now().setZone(timezone).hour;
  for (const [name, [start, end]] of Object.entries(WINDOWS)) if (h >= start && h < end) return name as any;
  return null;
}
export async function claimWindowQuest(playerId: string, timezone: string) {
  return db.tx(async tx => {
    const window = currentWindow(timezone);
    if (!window) throw new Error('no_active_window');
    const today = DateTime.now().setZone(timezone).toISODate();
    const col = `${window}_claimed`;
    const state = await tx.oneOrNone('SELECT * FROM player_window_quests WHERE player_id=$1 AND date=$2 FOR UPDATE', [playerId, today]);
    if (state && state[col]) throw new Error('already_claimed_this_window');
    await tx.none(`INSERT INTO player_window_quests(player_id, date, ${col}) VALUES ($1, $2, true) ON CONFLICT (player_id, date) DO UPDATE SET ${col} = true`, [playerId, today]);
    const fresh = await tx.one('SELECT * FROM player_window_quests WHERE player_id=$1 AND date=$2', [playerId, today]);
    let bonusGranted = false;
    if (fresh.morning_claimed && fresh.afternoon_claimed && fresh.evening_claimed) {
      const yesterday = DateTime.fromISO(today!).minus({ days: 1 }).toISODate();
      const prev = await tx.oneOrNone('SELECT perfect_streak FROM player_window_quests WHERE player_id=$1 AND date=$2', [playerId, yesterday]);
      const newStreak = (prev?.perfect_streak || 0) + 1;
      await tx.none('UPDATE player_window_quests SET perfect_streak=$1 WHERE player_id=$2 AND date=$3', [newStreak, playerId, today]);
      bonusGranted = true;
    }
    return { window, perfectDay: bonusGranted };
  });
}

