// src/services/smartPackService.ts
import { db } from '../db';
import { mulberry32, hashSeed } from '../lib/prng';
const PACK_STRUCTURE = [{ rarity: 'rare_or_mythic', count: 1 }, { rarity: 'uncommon', count: 3 }, { rarity: 'common', count: 4 }];
export async function openSmartPack(playerId: string, setCode: string, openSeed: string) {
  return db.tx(async tx => {
    const rand = mulberry32(hashSeed(`${playerId}:${setCode}:${openSeed}`));
    const ownedCounts = await tx.any('SELECT card_code, count FROM player_card_inventory WHERE player_id=$1 AND card_code IN (SELECT code FROM card_defs WHERE set=$2)', [playerId, setCode]);
    const countMap = new Map(ownedCounts.map(o => [o.card_code, o.count]));
    const result: any[] = [];
    for (const slot of PACK_STRUCTURE) {
      for (let i = 0; i < slot.count; i++) {
        let rarity: string;
        if (slot.rarity === 'rare_or_mythic') rarity = rand() < 0.125 ? 'mythic' : 'rare';
        else rarity = slot.rarity;
        const pool = await tx.any('SELECT code FROM card_defs WHERE set=$1 AND rarity=$2', [setCode, rarity]);
        const candidate = pool[Math.floor(rand() * pool.length)];
        const owned = countMap.get(candidate.code) || 0;
        if (owned >= 4) {
          await tx.none('INSERT INTO player_wildcards(player_id, rarity, count) VALUES ($1,$2,1) ON CONFLICT (player_id, rarity) DO UPDATE SET count = player_wildcards.count + 1', [playerId, rarity]);
          result.push({ originalCard: candidate.code, converted: true, rarity, type: 'wildcard' });
        } else {
          await tx.none('INSERT INTO player_card_inventory(player_id, card_code, count) VALUES ($1,$2,1) ON CONFLICT (player_id, card_code) DO UPDATE SET count = LEAST(4, player_card_inventory.count + 1)', [playerId, candidate.code]);
          countMap.set(candidate.code, owned + 1);
          result.push({ card: candidate.code, rarity, type: 'card' });
        }
      }
    }
    return { cards: result };
  });
}

