// src/services/globalRarityService.ts
import { redis } from '../redis';
import { db } from '../db';
export async function recordRareUnlock(playerId: string, achievementCode: string) {
  const position = await redis.incr(`global_achievement:${achievementCode}`);
  await db.none('INSERT INTO player_achievement_unlock(player_id, code, unlocked_at, position_at_unlock) VALUES ($1, $2, NOW(), $3) ON CONFLICT (player_id, code) DO NOTHING', [playerId, achievementCode, position]);
  await db.none('INSERT INTO global_achievement_count(code, count, last_updated) VALUES ($1, $2, NOW()) ON CONFLICT (code) DO UPDATE SET count=$2, last_updated=NOW()', [achievementCode, position]);
  const totalPlayers = await redis.get('player_count_estimate');
  const rarityPct = totalPlayers ? (position / parseInt(totalPlayers)) * 100 : null;
  return { position, rarityPct };
}

