import { db } from '../db';
import { validatePuzzleReplay } from '../shared/puzzleValidator';
export async function submitDailySolve(playerId: string, date: string, timeMs: number, replay: any[]) {
  const puzzle = await db.one('SELECT * FROM daily_puzzles WHERE date=$1', [date]);
  if (!validatePuzzleReplay(puzzle.puzzle_data, replay, puzzle.solution)) throw new Error('invalid_replay');
  await db.none('INSERT INTO player_daily_solves(player_id, date, time_ms, solved_at, replay) VALUES ($1, $2, $3, NOW(), $4) ON CONFLICT (player_id, date) DO NOTHING', [playerId, date, timeMs, JSON.stringify(replay)]);
}
export async function getLeaderboard(date: string, viewerId: string, scope: 'global' | 'friends') {
  let rows;
  if (scope === 'global') {
    rows = await db.any('SELECT p.name, pds.time_ms, pds.player_id FROM player_daily_solves pds JOIN players p ON p.id=pds.player_id WHERE pds.date=$1 ORDER BY pds.time_ms ASC LIMIT 100', [date]);
  } else {
    rows = await db.any(`SELECT p.name, pds.time_ms, pds.player_id FROM player_daily_solves pds JOIN players p ON p.id=pds.player_id JOIN friendships f ON (f.player_a=$2 AND f.player_b=pds.player_id) OR (f.player_b=$2 AND f.player_a=pds.player_id) WHERE pds.date=$1 ORDER BY pds.time_ms ASC`, [date, viewerId]);
  }
  return rows.map((r: any, i: number) => ({ rank: i + 1, name: r.name, time_ms: r.time_ms, is_me: r.player_id === viewerId }));
}

