// src/jobs/massNotificationBroadcaster.ts
import { Queue, Worker } from 'bullmq';
import { db } from '../db';
import { sendPush } from '../services/pushDispatcher';
const broadcastQueue = new Queue('mass-broadcast');
export async function scheduleBroadcast(eventId: string, payload: any) {
  const recipients = await db.any('SELECT player_id, timezone FROM player_notification_prefs WHERE push_enabled = true AND notification_prefs->>$2 != $3', ['', 'events', 'off']);
  const broadcast = await db.one('INSERT INTO event_broadcasts(event_id, scheduled_for, recipients_total) VALUES ($1, NOW(), $2) RETURNING id', [eventId, recipients.length]);
  const filtered = recipients.filter(r => inAwakeWindow(r.timezone));
  const shuffled = [...filtered].sort(() => Math.random() - 0.5);
  const waveSize = Math.ceil(shuffled.length / 60);
  for (let i = 0; i < 60; i++) {
    const wave = shuffled.slice(i * waveSize, (i + 1) * waveSize);
    await broadcastQueue.add('wave', { broadcastId: broadcast.id, recipientIds: wave.map(w => w.player_id), payload }, { delay: i * 1000 });
  }
}
function inAwakeWindow(timezone: string): boolean {
  const h = new Date(new Date().toLocaleString('en-US', { timeZone: timezone })).getHours();
  return h >= 8 && h < 22;
}
new Worker('mass-broadcast', async job => {
  if (job.name !== 'wave') return;
  const { broadcastId, recipientIds, payload } = job.data;
  await Promise.all(recipientIds.map(async (pid: string) => {
    try { await sendPush(pid, payload); await db.none('INSERT INTO broadcast_recipients(broadcast_id, player_id, sent) VALUES ($1, $2, true) ON CONFLICT DO NOTHING', [broadcastId, pid]); }
    catch (e) { await db.none('INSERT INTO broadcast_recipients(broadcast_id, player_id, sent) VALUES ($1, $2, false)', [broadcastId, pid]); }
  }));
  await db.none('UPDATE event_broadcasts SET sent_count = sent_count + $1 WHERE id=$2', [recipientIds.length, broadcastId]);
}, { concurrency: 10 });

