// src/components/EventBanner.tsx — in-app counterpart
import useSWR from 'swr';
import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
export function EventBanner() {
  const { data } = useSWR('/api/events/upcoming', u => fetch(u).then(r => r.json()));
  const [dismissed, setDismissed] = useState(false);
  const [timeLeft, setTimeLeft] = useState('');
  useEffect(() => {
    if (!data?.next_event) return;
    const tick = () => {
      const ms = new Date(data.next_event.starts_at).getTime() - Date.now();
      if (ms <= 0) return setTimeLeft('LIVE');
      const m = Math.floor(ms / 60000);
      const s = Math.floor((ms % 60000) / 1000);
      setTimeLeft(`${m}m ${s}s`);
    };
    tick(); const id = setInterval(tick, 1000); return () => clearInterval(id);
  }, [data]);
  if (!data?.next_event || dismissed) return null;
  return (
    <motion.div initial={{ y: -100 }} animate={{ y: 0 }} className='fixed top-0 left-0 right-0 p-3 bg-gradient-to-r from-fuchsia-600 to-orange-500 text-white text-center z-40'>
      <span className='font-bold'>{data.next_event.name}</span> starts in <span className='font-mono'>{timeLeft}</span>
      <button onClick={() => setDismissed(true)} className='ml-3 text-xs opacity-70'>dismiss</button>
    </motion.div>
  );
}

