// src/services/shopRotationService.ts
import { db } from '../db';
import { sendPush } from './pushDispatcher';
export async function rotateShop() {
  const today = new Date().toISOString().slice(0, 10);
  const existing = await db.oneOrNone('SELECT 1 FROM daily_shop_rotation WHERE date=$1', [today]);
  if (existing) return;
  const allItems = await db.any('SELECT * FROM shop_items WHERE active=true');
  const recent = await db.any('SELECT items FROM daily_shop_rotation WHERE date > NOW() - INTERVAL '14 days'');
  const recentCodes = new Set<string>();
  for (const r of recent) for (const i of r.items) recentCodes.add(i);
  const eligible = allItems.filter(i => !recentCodes.has(i.code));
  const chosen = eligible.sort(() => Math.random() - 0.5).slice(0, 8);
  await db.none('INSERT INTO daily_shop_rotation(date, items) VALUES ($1, $2)', [today, JSON.stringify(chosen.map(c => c.code))]);
  for (const item of chosen) {
    const watchers = await db.any('SELECT player_id FROM player_wishlist WHERE item_code=$1', [item.code]);
    for (const w of watchers) {
      const notifSent = await db.oneOrNone('SELECT 1 FROM shop_notifications WHERE player_id=$1 AND item_code=$2 AND sent_at > NOW() - INTERVAL '7 days'', [w.player_id, item.code]);
      if (notifSent) continue;
      await sendPush(w.player_id, { title: 'Item you wanted is live!', body: `${item.name} is in the shop today`, image_url: item.icon_url, deep_link: `/shop/${item.code}` });
      await db.none('INSERT INTO shop_notifications(player_id, item_code, sent_at) VALUES ($1, $2, NOW())', [w.player_id, item.code]);
    }
  }
}
export async function addToWishlist(playerId: string, itemCode: string) {
  const count = await db.one('SELECT COUNT(*) FROM player_wishlist WHERE player_id=$1', [playerId]);
  if (Number(count.count) >= 20) throw new Error('wishlist_full');
  await db.none('INSERT INTO player_wishlist(player_id, item_code, added_at) VALUES ($1, $2, NOW()) ON CONFLICT DO NOTHING', [playerId, itemCode]);
}

