// src/services/speedrunService.ts
import { db } from '../db';
export async function submitSplit(playerId: string, attemptId: string, segmentIdx: number, splitMs: number) {
  await db.none(`UPDATE speedrun_attempts SET splits[$1] = $2 WHERE id=$3 AND player_id=$4`, [segmentIdx + 1, splitMs, attemptId, playerId]);
}
export async function completeRun(playerId: string, attemptId: string) {
  return db.tx(async tx => {
    const attempt = await tx.one('SELECT * FROM speedrun_attempts WHERE id=$1 FOR UPDATE', [attemptId]);
    if (attempt.completed) throw new Error('already_completed');
    const total = attempt.splits.reduce((s: number, x: number) => s + x, 0);
    await tx.none('UPDATE speedrun_attempts SET completed=true, total_time=$1, submitted_at=NOW() WHERE id=$2', [total, attemptId]);
    const pb = await tx.oneOrNone('SELECT total_time FROM player_pb WHERE player_id=$1 AND category_id=$2', [playerId, attempt.category_id]);
    if (!pb || total < pb.total_time) {
      await tx.none('INSERT INTO player_pb(player_id, category_id, splits, total_time) VALUES ($1, $2, $3, $4) ON CONFLICT (player_id, category_id) DO UPDATE SET splits=$3, total_time=$4', [playerId, attempt.category_id, attempt.splits, total]);
    }
    return { newPb: !pb || total < pb.total_time, total };
  });
}
export async function getRunStats(playerId: string, categoryId: string) {
  const pb = await db.oneOrNone('SELECT * FROM player_pb WHERE player_id=$1 AND category_id=$2', [playerId, categoryId]);
  const wr = await db.oneOrNone('SELECT splits, total_time FROM player_pb WHERE category_id=$1 ORDER BY total_time ASC LIMIT 1', [categoryId]);
  const allAttempts = await db.any('SELECT splits FROM speedrun_attempts WHERE player_id=$1 AND category_id=$2 AND completed=true', [playerId, categoryId]);
  const segmentCount = pb?.splits.length || 0;
  const sumOfBest: number[] = [];
  for (let i = 0; i < segmentCount; i++) {
    sumOfBest[i] = Math.min(...allAttempts.map(a => a.splits[i] || Infinity).filter((x: number) => isFinite(x)));
  }
  return { pb, wr, sumOfBest, sumOfBestTotal: sumOfBest.reduce((s, x) => s + x, 0) };
}

