// src/services/asymmetricMatchmaker.ts
import { redis } from '../redis';
import { db } from '../db';
export async function queueAsymmetric(playerId: string, role: 'killer' | 'survivor', rating: number) {
  await redis.zadd(`asym:queue:${role}`, rating, playerId);
  return tryFormMatch();
}
async function tryFormMatch() {
  const killers = await redis.zrange('asym:queue:killer', 0, -1, 'WITHSCORES');
  const survivors = await redis.zrange('asym:queue:survivor', 0, -1, 'WITHSCORES');
  if (killers.length < 2 || survivors.length < 8) return null;
  for (let i = 0; i < killers.length; i += 2) {
    const killerId = killers[i]; const killerRating = parseFloat(killers[i + 1]);
    const matchingSurvivors: string[] = [];
    for (let j = 0; j < survivors.length && matchingSurvivors.length < 4; j += 2) {
      const sRating = parseFloat(survivors[j + 1]);
      if (Math.abs(sRating - killerRating) < 200) matchingSurvivors.push(survivors[j]);
    }
    if (matchingSurvivors.length === 4) {
      await redis.zrem('asym:queue:killer', killerId);
      for (const s of matchingSurvivors) await redis.zrem('asym:queue:survivor', s);
      const match = await db.one('INSERT INTO asym_matches(killer_id, survivor_ids) VALUES ($1, $2) RETURNING id', [killerId, matchingSurvivors]);
      return match.id;
    }
  }
  return null;
}
export async function getQueueImbalance(): Promise<{ ratio: number; bonus: boolean }> {
  const k = await redis.zcard('asym:queue:killer');
  const s = await redis.zcard('asym:queue:survivor');
  const ratio = s / Math.max(k, 1);
  return { ratio, bonus: ratio > 5 };
}

