import { db } from '../db';
import { redis } from '../redis';
import { io } from '../socket';
export async function checkIn(playerId: string, arenaId: string) {
  await db.none('INSERT INTO arena_players(arena_id, player_id, available) VALUES ($1, $2, true) ON CONFLICT (arena_id, player_id) DO UPDATE SET available=true', [arenaId, playerId]);
}
export async function pairPlayers(arenaId: string) {
  const available = await db.any('SELECT p.player_id, pr.rating FROM arena_players p JOIN player_role_rating pr ON pr.player_id = p.player_id WHERE p.arena_id=$1 AND p.available=true ORDER BY pr.rating', [arenaId]);
  const pairs: Array<[string, string]> = [];
  const used = new Set<string>();
  for (let i = 0; i < available.length - 1; i++) {
    if (used.has(available[i].player_id)) continue;
    for (let j = i + 1; j < available.length; j++) {
      if (used.has(available[j].player_id)) continue;
      pairs.push([available[i].player_id, available[j].player_id]);
      used.add(available[i].player_id); used.add(available[j].player_id);
      break;
    }
  }
  for (const [a, b] of pairs) {
    const game = await db.one('INSERT INTO arena_games(arena_id, white_id, black_id) VALUES ($1, $2, $3) RETURNING id', [arenaId, a, b]);
    await db.none('UPDATE arena_players SET available=false WHERE arena_id=$1 AND player_id IN ($2, $3)', [arenaId, a, b]);
    io.to(`arena:${arenaId}`).emit('paired', { gameId: game.id, players: [a, b] });
  }
}
export async function reportArenaResult(gameId: string, result: 'white' | 'black' | 'draw') {
  return db.tx(async tx => {
    const game = await tx.one('SELECT * FROM arena_games WHERE id=$1', [gameId]);
    await tx.none('UPDATE arena_games SET result=$1, ended_at=NOW() WHERE id=$2', [result, gameId]);
    for (const [pid, won] of [[game.white_id, result === 'white'], [game.black_id, result === 'black']]) {
      const player = await tx.one('SELECT score, streak FROM arena_players WHERE arena_id=$1 AND player_id=$2 FOR UPDATE', [game.arena_id, pid]);
      let points = 0; let newStreak = 0;
      if (result === 'draw') { points = 1; newStreak = 0; }
      else if (won) { newStreak = player.streak + 1; points = newStreak >= 3 ? 4 : 2; }
      else { newStreak = 0; points = 0; }
      await tx.none('UPDATE arena_players SET score=$1, streak=$2, available=true, games_played=games_played+1 WHERE arena_id=$3 AND player_id=$4', [player.score + points, newStreak, game.arena_id, pid]);
      await redis.zadd(`arena:lb:${game.arena_id}`, player.score + points, pid);
    }
    io.to(`arena:${game.arena_id}`).emit('leaderboard_update');
  });
}

