import { db } from '../db';
export async function checkReturningPlayer(playerId: string) {
  const player = await db.one('SELECT id, last_login_at, current_season FROM players WHERE id=$1', [playerId]);
  const lastLogin = new Date(player.last_login_at);
  const daysSince = (Date.now() - lastLogin.getTime()) / 86400000;
  if (daysSince < 30) return null;
  const currentSeason = await db.one('SELECT current_season FROM game_config');
  const missedSeasons: number[] = [];
  for (let s = player.current_season + 1; s < currentSeason.current_season; s++) missedSeasons.push(s);
  if (missedSeasons.length === 0) return null;
  await db.tx(async tx => {
    const expiry = new Date(Date.now() + 14 * 86400000);
    await tx.none('INSERT INTO player_return_status(player_id, last_active_at, catch_up_active_until, missed_seasons) VALUES ($1, $2, $3, $4) ON CONFLICT (player_id) DO UPDATE SET catch_up_active_until=$3, missed_seasons=$4', [playerId, lastLogin, expiry, missedSeasons]);
    const missedCosmetics = await tx.any('SELECT cosmetic_code FROM season_cosmetics WHERE season = ANY($1)', [missedSeasons]);
    for (const c of missedCosmetics) {
      await tx.none('INSERT INTO time_capsule_offers(player_id, cosmetic_code, expires_at) VALUES ($1, $2, $3) ON CONFLICT (player_id, cosmetic_code) DO UPDATE SET expires_at=$3', [playerId, c.cosmetic_code, expiry]);
    }
  });
  return { missedSeasons, catchUpUntil: new Date(Date.now() + 14 * 86400000) };
}
export async function purchaseTimeCapsuleItem(playerId: string, cosmeticCode: string) {
  return db.tx(async tx => {
    const offer = await tx.oneOrNone('SELECT * FROM time_capsule_offers WHERE player_id=$1 AND cosmetic_code=$2 AND expires_at > NOW()', [playerId, cosmeticCode]);
    if (!offer) throw new Error('offer_expired');
    const cosmetic = await tx.one('SELECT base_price FROM season_cosmetics WHERE cosmetic_code=$1', [cosmeticCode]);
    const discountPrice = Math.floor(cosmetic.base_price * 0.5);
    await applyCurrencyChange({ playerId, currency: 'hard', delta: -discountPrice, reason: 'time_capsule', referenceId: cosmeticCode, idempotencyKey: `tc:${playerId}:${cosmeticCode}` });
    await tx.none('INSERT INTO player_cosmetics(player_id, cosmetic_code) VALUES ($1, $2) ON CONFLICT DO NOTHING', [playerId, cosmeticCode]);
  });
}

