// src/services/coopSyncService.ts
import { redis } from '../redis';
import { io } from '../socket';
export async function applyCoopAction(sessionId: string, playerId: string, action: { type: string; target: string; value: any }) {
  const lockKey = `coop:lock:${sessionId}`;
  const acquired = await redis.set(lockKey, playerId, 'PX', 1000, 'NX');
  if (!acquired) throw new Error('concurrent_action');
  try {
    const stateJson = await redis.get(`coop:state:${sessionId}`);
    const state = stateJson ? JSON.parse(stateJson) : {};
    if (action.type === 'lever_toggle') {
      state[action.target] = !state[action.target];
      if (action.target === 'lever_a') state['door_b'] = state['lever_a'];
    } else if (action.type === 'pickup') {
      if (state.held_by_a === action.target || state.held_by_b === action.target) throw new Error('already_held');
      state[playerId === 'a' ? 'held_by_a' : 'held_by_b'] = action.target;
    }
    await redis.set(`coop:state:${sessionId}`, JSON.stringify(state));
    io.to(`coop:${sessionId}`).emit('state_update', { state, by: playerId, action });
  } finally {
    await redis.del(lockKey);
  }
}

