// src/services/enemyAffixGenerator.ts
import { db } from '../db';
import { mulberry32, hashSeed } from '../lib/prng';
export async function generateEnemyAffixes(baseEnemyCode: string, difficulty: number, spawnSeed: string) {
  const rand = mulberry32(hashSeed(`${baseEnemyCode}:${spawnSeed}`));
  const affixes = await db.any('SELECT * FROM enemy_affixes');
  const forbidden = await db.any('SELECT * FROM forbidden_combinations');
  const forbiddenMap = new Map<string, Set<string>>();
  for (const f of forbidden) { if (!forbiddenMap.has(f.affix_a)) forbiddenMap.set(f.affix_a, new Set()); forbiddenMap.get(f.affix_a)!.add(f.affix_b); }
  const affixCount = Math.min(4, Math.floor(rand() * difficulty) + 1);
  const chosen: string[] = [];
  const pool = [...affixes].sort(() => rand() - 0.5);
  for (const a of pool) {
    if (chosen.length >= affixCount) break;
    const incompatible = chosen.some(c => forbiddenMap.get(c)?.has(a.code) || forbiddenMap.get(a.code)?.has(c));
    if (incompatible) continue;
    chosen.push(a.code);
  }
  const power = chosen.reduce((s, c) => s + (affixes.find(a => a.code === c)?.power_value || 0), 0);
  const maxPower = 10 + difficulty * 5;
  if (power > maxPower) chosen.pop();
  return chosen;
}

