// src/components/RTSHud.tsx
import { useEffect, useState, useRef } from 'react';
export function RTSHud({ worldSize, cameraPos, onCameraMove, units, selectedUnits, onSelect, resources }: any) {
  const minimapRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const canvas = minimapRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d')!;
    const w = canvas.width; const h = canvas.height;
    const scaleX = w / worldSize.width; const scaleY = h / worldSize.height;
    ctx.fillStyle = '#0f172a'; ctx.fillRect(0, 0, w, h);
    for (const u of units) {
      ctx.fillStyle = u.owner === 'me' ? '#06b6d4' : '#ef4444';
      ctx.fillRect(u.x * scaleX - 1, u.y * scaleY - 1, 3, 3);
    }
    ctx.strokeStyle = '#facc15'; ctx.lineWidth = 1;
    ctx.strokeRect(cameraPos.x * scaleX, cameraPos.y * scaleY, cameraPos.width * scaleX, cameraPos.height * scaleY);
  }, [units, cameraPos]);
  const onMinimapClick = (e: any) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width * worldSize.width;
    const y = (e.clientY - rect.top) / rect.height * worldSize.height;
    onCameraMove(x, y);
  };
  const [hotkeyGroups, setHotkeyGroups] = useState<Record<number, string[]>>({});
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      const num = parseInt(e.key);
      if (isNaN(num) || num < 0 || num > 9) return;
      if (e.ctrlKey) setHotkeyGroups(g => ({ ...g, [num]: selectedUnits.map((u: any) => u.id) }));
      else if (hotkeyGroups[num]) onSelect(hotkeyGroups[num]);
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [selectedUnits, hotkeyGroups]);
  return (
    <>
      <div className='absolute top-2 left-2 flex gap-3 text-white text-sm font-bold'>
        <span>🪙 {resources.gold}</span>
        <span>🪵 {resources.wood}</span>
        <span>⛏️ {resources.stone}</span>
      </div>
      <canvas ref={minimapRef} width={200} height={200} className='absolute bottom-2 right-2 border-2 border-slate-700' onClick={onMinimapClick} />
      <div className='absolute bottom-2 left-2 flex gap-1'>
        {Object.entries(hotkeyGroups).map(([id, units]) => (
          <div key={id} className='px-2 py-1 bg-slate-800 rounded text-xs text-white'>[{id}] {units.length}</div>
        ))}
      </div>
    </>
  );
}

