export async function processWarResult(warId: string, winnerGuild: string, scoreA: number, scoreB: number) {
  return db.tx(async tx => {
    const war = await tx.one('SELECT * FROM guild_war_declarations WHERE id=$1', [warId]);
    const a = war.attacker_id < war.defender_id ? war.attacker_id : war.defender_id;
    const b = war.attacker_id < war.defender_id ? war.defender_id : war.attacker_id;
    const rivalry = await tx.oneOrNone('SELECT * FROM guild_rivalries WHERE guild_a=$1 AND guild_b=$2 FOR UPDATE', [a, b]);
    if (!rivalry) return;
    const margin = Math.abs(scoreA - scoreB);
    const isAWin = winnerGuild === a;
    await tx.none(`UPDATE guild_rivalries SET wars_count = wars_count + 1, a_wins = a_wins + $1, b_wins = b_wins + $2, biggest_a_margin = GREATEST(biggest_a_margin, $3), biggest_b_margin = GREATEST(biggest_b_margin, $4), current_streak_guild = CASE WHEN current_streak_guild=$5 THEN current_streak_guild ELSE $5 END, current_streak = CASE WHEN current_streak_guild=$5 THEN current_streak + 1 ELSE 1 END WHERE id=$6`,
      [isAWin ? 1 : 0, isAWin ? 0 : 1, isAWin ? margin : 0, isAWin ? 0 : margin, winnerGuild, rivalry.id]);
    await tx.none('INSERT INTO rivalry_war_log(rivalry_id, war_id, winner, score_a, score_b) VALUES ($1, $2, $3, $4, $5)', [rivalry.id, warId, winnerGuild, scoreA, scoreB]);
  });
}

// src/jobs/marketBotDetector.ts
import { Worker } from 'bullmq';
import { db } from '../db';
new Worker('market-bot-detector', async () => {
  const players = await db.any('SELECT DISTINCT player_id FROM market_action_log WHERE ts > NOW() - INTERVAL '24 hours'');
  for (const p of players) {
    const actions = await db.any('SELECT * FROM market_action_log WHERE player_id=$1 AND ts > NOW() - INTERVAL '24 hours' ORDER BY ts', [p.player_id]);
    if (actions.length < 50) continue;
    const deltas: number[] = [];
    for (let i = 1; i < actions.length; i++) deltas.push(new Date(actions[i].ts).getTime() - new Date(actions[i - 1].ts).getTime());
    const mean = deltas.reduce((s, x) => s + x, 0) / deltas.length;
    const std = Math.sqrt(deltas.reduce((s, x) => s + (x - mean) ** 2, 0) / deltas.length);
    const cv = std / mean;
    const itemDiversity = new Set(actions.map(a => a.item_code)).size / actions.length;
    const idleGaps = deltas.filter(d => d > 3600000).length;
    let score = 0;
    if (cv < 0.3) score += 3;
    if (itemDiversity < 0.05) score += 2;
    if (idleGaps === 0 && actions.length > 200) score += 3;
    await db.none('INSERT INTO bot_scores(player_id, score, computed_at, restricted) VALUES ($1, $2, NOW(), $3) ON CONFLICT (player_id) DO UPDATE SET score=$2, computed_at=NOW(), restricted=$3', [p.player_id, score, score >= 5]);
  }
});

