// src/services/chestService.ts
import { db } from '../db';
const TIER_HOURS: any = { common: 1, rare: 4, epic: 8, legendary: 24 };
export async function awardChest(playerId: string, tier: string) {
  return db.tx(async tx => {
    const slots = await tx.any('SELECT * FROM player_chest_slots WHERE player_id=$1 ORDER BY slot_idx', [playerId]);
    const emptySlot = slots.find((s: any) => !s.chest_tier);
    if (emptySlot) {
      const unlockAt = new Date(Date.now() + TIER_HOURS[tier] * 3600 * 1000);
      await tx.none('UPDATE player_chest_slots SET chest_tier=$1, unlock_at=$2 WHERE player_id=$3 AND slot_idx=$4', [tier, unlockAt, playerId, emptySlot.slot_idx]);
      return { placed: 'slot', slotIdx: emptySlot.slot_idx };
    } else {
      await tx.none('INSERT INTO player_chest_queue(player_id, chest_tier) VALUES ($1, $2)', [playerId, tier]);
      return { placed: 'queue' };
    }
  });
}
export async function openChest(playerId: string, slotIdx: number) {
  return db.tx(async tx => {
    const slot = await tx.one('SELECT * FROM player_chest_slots WHERE player_id=$1 AND slot_idx=$2 FOR UPDATE', [playerId, slotIdx]);
    if (slot.unlock_at > new Date()) throw new Error('not_unlocked');
    if (!slot.chest_tier) throw new Error('no_chest');
    const rewards = await generateChestRewards(tx, playerId, slot.chest_tier);
    await tx.none('UPDATE player_chest_slots SET chest_tier=NULL, unlock_at=NULL WHERE player_id=$1 AND slot_idx=$2', [playerId, slotIdx]);
    const queued = await tx.oneOrNone('SELECT * FROM player_chest_queue WHERE player_id=$1 ORDER BY earned_at LIMIT 1', [playerId]);
    if (queued) {
      await tx.none('DELETE FROM player_chest_queue WHERE id=$1', [queued.id]);
      const unlockAt = new Date(Date.now() + TIER_HOURS[queued.chest_tier] * 3600 * 1000);
      await tx.none('UPDATE player_chest_slots SET chest_tier=$1, unlock_at=$2 WHERE player_id=$3 AND slot_idx=$4', [queued.chest_tier, unlockAt, playerId, slotIdx]);
    }
    return { rewards };
  });
}
export async function skipChestTimer(playerId: string, slotIdx: number) {
  return db.tx(async tx => {
    const slot = await tx.one('SELECT * FROM player_chest_slots WHERE player_id=$1 AND slot_idx=$2 FOR UPDATE', [playerId, slotIdx]);
    const remainingMin = Math.max(0, (new Date(slot.unlock_at).getTime() - Date.now()) / 60000);
    const cost = Math.floor(remainingMin / 10);
    await applyCurrencyChange({ playerId, currency: 'hard', delta: -cost, reason: 'skip_chest', referenceId: `slot:${slotIdx}`, idempotencyKey: `skip:${playerId}:${slotIdx}:${Date.now()}` });
    await tx.none('UPDATE player_chest_slots SET unlock_at=NOW() WHERE player_id=$1 AND slot_idx=$2', [playerId, slotIdx]);
    return { cost };
  });
}
async function generateChestRewards(tx: any, playerId: string, tier: string) { return { gold: 100, items: [] }; }

