// src/services/multiQueueMatchmaker.ts
import { redis } from '../redis';
import { db } from '../db';
export async function queueMode(playerId: string, mode: string, allowBackfill = false) {
  const rating = await db.one('SELECT rating FROM player_mode_rating WHERE player_id=$1 AND mode=$2', [playerId, mode]);
  await redis.zadd(`mm:${mode}`, rating.rating, playerId);
  const startMs = Date.now();
  while (Date.now() - startMs < 60000) {
    const candidates = await redis.zrangebyscore(`mm:${mode}`, rating.rating - 100, rating.rating + 100);
    if (candidates.length >= 2) {
      const match = candidates.filter(c => c !== playerId).slice(0, 1);
      await redis.zrem(`mm:${mode}`, playerId);
      await redis.zrem(`mm:${mode}`, match[0]);
      return { mode, opponents: match };
    }
    if (allowBackfill && (Date.now() - startMs) > 30000 && mode === '1v1') {
      const team = await redis.zrangebyscore(`mm:2v2`, rating.rating * 0.95 - 100, rating.rating * 0.95 + 100);
      if (team.length >= 3) {
        await redis.zrem('mm:1v1', playerId);
        for (const t of team.slice(0, 3)) await redis.zrem('mm:2v2', t);
        return { mode: '2v2_backfill', team: team.slice(0, 3).concat([playerId]) };
      }
    }
    await new Promise(r => setTimeout(r, 1000));
  }
  await redis.zrem(`mm:${mode}`, playerId);
  return { timedOut: true };
}

