// src/services/procQuestService.ts
import { db } from '../db';
import { mulberry32, hashSeed } from '../lib/prng';
export async function generateProcQuest(playerId: string, zone: string) {
  const seed = hashSeed(`${playerId}:${Date.now()}`);
  const rand = mulberry32(seed);
  const templates = await db.any('SELECT * FROM quest_templates');
  const template = templates[Math.floor(rand() * templates.length)];
  const variables: any = {};
  for (const [key, schema] of Object.entries<any>(template.variables_schema)) {
    if (schema.type === 'creature') {
      const opts = await db.any('SELECT * FROM creatures WHERE zone=$1', [zone]);
      variables[key] = opts[Math.floor(rand() * opts.length)].code;
    } else if (schema.type === 'npc') {
      const opts = await db.any('SELECT * FROM npcs WHERE zone=$1 AND alive=true', [zone]);
      variables[key] = opts[Math.floor(rand() * opts.length)].id;
    } else if (schema.type === 'count') variables[key] = schema.min + Math.floor(rand() * (schema.max - schema.min));
  }
  const filledText = (template.template as string).replace(/{(\w+)}/g, (_, k) => variables[k]);
  const narrative = await generateNarrative(filledText, rand);
  const quest = await db.one('INSERT INTO proc_quests(player_id, template_id, variables, generated_text, objective, status) VALUES ($1, $2, $3, $4, $5, $6) RETURNING *', [playerId, template.id, JSON.stringify(variables), narrative, JSON.stringify(template.objective), 'active']);
  return quest;
}
async function generateNarrative(seed: string, rand: () => number): Promise<string> {
  return `Word has it that ${seed}. The contract pays well, but the danger is real. Will you accept?`;
}

