import useSWR from 'swr';
export function ContractDetail({ questId }: any) {
  const { data } = useSWR(`/api/proc-quest/${questId}`, u => fetch(u).then(r => r.json()));
  if (!data) return null;
  return (
    <div className='max-w-2xl p-6 bg-amber-50 text-stone-900 font-serif'>
      <div className='text-xs uppercase tracking-widest text-stone-600'>Contract</div>
      <h2 className='text-2xl font-bold mt-1'>{data.title || 'Open Contract'}</h2>
      <p className='mt-4 leading-relaxed'>{data.generated_text}</p>
      <div className='mt-6 p-4 bg-amber-100 border border-amber-300 rounded'>
        <div className='text-xs uppercase tracking-widest text-amber-900'>Objective</div>
        <div className='mt-1'>{data.objective_description}</div>
        <div className='mt-2 text-sm text-emerald-700 font-bold'>Reward: {data.reward}</div>
      </div>
      <button className='mt-4 px-4 py-2 bg-stone-900 text-amber-50 rounded'>Accept Contract</button>
    </div>
  );
}

