// src/jobs/metaAnalytics.ts
import { Worker } from 'bullmq';
import { db } from '../db';
new Worker('meta-analytics', async () => {
  await db.none('TRUNCATE matchup_stats');
  const matchups = await db.any(`SELECT deck_a_archetype, deck_b_archetype, COUNT(*) FILTER (WHERE winner='a') AS wins_a, COUNT(*) AS total FROM match_results WHERE ended_at > NOW() - INTERVAL '7 days' GROUP BY deck_a_archetype, deck_b_archetype HAVING COUNT(*) >= 50`);
  for (const m of matchups) await db.none('INSERT INTO matchup_stats(archetype_a, archetype_b, wins_a, total) VALUES ($1, $2, $3, $4)', [m.deck_a_archetype, m.deck_b_archetype, m.wins_a, m.total]);
});
export async function getMatchupForDeck(archetypeId: string) {
  return db.any('SELECT archetype_b, wins_a::float / total AS win_rate FROM matchup_stats WHERE archetype_a=$1 ORDER BY win_rate', [archetypeId]);
}
export async function getCounterCards(archetypeToCounter: string) {
  return db.any(`SELECT card_code, win_rate FROM card_in_deck_stats cs WHERE archetype != $1 AND EXISTS (SELECT 1 FROM matchup_stats m WHERE m.archetype_a = cs.archetype AND m.archetype_b = $1 AND m.wins_a::float / m.total > 0.55) ORDER BY win_rate DESC LIMIT 10`, [archetypeToCounter]);
}

