// src/components/MetaDashboard.tsx
import useSWR from 'swr';
export function MetaDashboard() {
  const { data: tiers } = useSWR('/api/meta/tier-list', u => fetch(u).then(r => r.json()));
  const { data: matchups } = useSWR('/api/meta/matchup-matrix', u => fetch(u).then(r => r.json()));
