        <h2 className='text-xl font-bold text-white mb-3'>Top Decks This Week</h2>
        <div className='space-y-2'>
          {tiers.map((d: any, i: number) => (
            <div key={d.archetype_id} className='flex items-center justify-between p-3 bg-slate-900 rounded'>
              <div className='flex items-center gap-3'>
                <span className='font-mono text-slate-400 w-8'>#{i + 1}</span>
                <span className='text-white font-bold'>{d.name}</span>
              </div>
              <div className='flex items-center gap-3 text-sm'>
                <span className='text-emerald-400 font-mono'>{(d.win_rate * 100).toFixed(1)}%</span>
                <span className='text-slate-400'>{d.play_rate.toFixed(1)}% played</span>
              </div>
            </div>
          ))}
        </div>
      </section>
      <section>
        <h2 className='text-xl font-bold text-white mb-3'>Matchup Matrix</h2>
        <table className='w-full text-xs'>
          <tbody>
            {matchups.map((row: any, i: number) => (
              <tr key={i}>
                <td className='text-right pr-2 text-slate-400'>{row.archetype}</td>
                {row.matchups.map((wr: number, j: number) => (
                  <td key={j} className='p-1' style={{ background: wr > 0.5 ? `rgba(16, 185, 129, ${(wr - 0.5) * 2})` : `rgba(239, 68, 68, ${(0.5 - wr) * 2})` }} title={`${(wr * 100).toFixed(0)}%`}><span className='text-white font-mono'>{(wr * 100).toFixed(0)}</span></td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </div>
  );
}

