export async function resolveGameFeature(input: GameInput, services: GameServices): Promise<GameResult> {
  const validated = GameInputSchema.parse(input);
  const state = await services.state.load(validated.playerId);
  const result = applyDeterministicRules(state, validated, services.clock.now());
  await services.audit.write({ playerId: validated.playerId, event: 'game-074', result });
  return result;
}

// The feature is deterministic, auditable, and server-validatable even when the presentation is mostly client-side.

