// src/game/physics.ts
export interface Entity { id: string; x: number; y: number; z: number; vx: number; vy: number; vz: number; radius: number; }
export class PhysicsWorld {
  entities = new Map<string, Entity>();
  cellSize = 2;
  step(dt: number) {
    for (const e of this.entities.values()) { e.x += e.vx * dt; e.y += e.vy * dt; e.z += e.vz * dt; }
    const hash = new Map<string, Entity[]>();
    for (const e of this.entities.values()) {
      const cx = Math.floor(e.x / this.cellSize); const cy = Math.floor(e.y / this.cellSize); const cz = Math.floor(e.z / this.cellSize);
      const key = `${cx},${cy},${cz}`;
      if (!hash.has(key)) hash.set(key, []);
      hash.get(key)!.push(e);
    }
    for (const cell of hash.values()) {
      if (cell.length < 2) continue;
      for (let i = 0; i < cell.length; i++) {
        for (let j = i + 1; j < cell.length; j++) {
          const a = cell[i]; const b = cell[j];
          const dx = b.x - a.x; const dy = b.y - a.y; const dz = b.z - a.z;
          const d = Math.sqrt(dx*dx + dy*dy + dz*dz);
          if (d < a.radius + b.radius) this.resolveCollision(a, b, dx, dy, dz, d);
        }
      }
    }
  }
  resolveCollision(a: Entity, b: Entity, dx: number, dy: number, dz: number, d: number) {
    if (d === 0) return;
    const overlap = (a.radius + b.radius) - d;
    const nx = dx / d; const ny = dy / d; const nz = dz / d;
    a.x -= nx * overlap * 0.5; a.y -= ny * overlap * 0.5; a.z -= nz * overlap * 0.5;
    b.x += nx * overlap * 0.5; b.y += ny * overlap * 0.5; b.z += nz * overlap * 0.5;
    const dvx = b.vx - a.vx; const dvy = b.vy - a.vy; const dvz = b.vz - a.vz;
    const dvn = dvx * nx + dvy * ny + dvz * nz;
    if (dvn > 0) return;
    a.vx += dvn * nx; a.vy += dvn * ny; a.vz += dvn * nz;
    b.vx -= dvn * nx; b.vy -= dvn * ny; b.vz -= dvn * nz;
  }
}

import { useFrame } from '@react-three/fiber';
import { useRef } from 'react';
export function PhysicsBodies({ entities }: any) {
  const worldRef = useRef(new PhysicsWorld());
  useFrame((_, dt) => { worldRef.current.step(dt); });
  return <>{Array.from(worldRef.current.entities.values()).map(e => <mesh key={e.id} position={[e.x, e.y, e.z]}><sphereGeometry args={[e.radius]} /><meshBasicMaterial color='cyan' /></mesh>)}</>;
}

