// src/services/presenceService.ts
import { redis } from '../redis';
import { db } from '../db';
import { io } from '../socket';
export async function updatePresence(playerId: string, device: string, status: string) {
  await redis.hset(`presence:${playerId}`, { online: 'true', device, status_text: status, last_active: Date.now().toString() });
  await redis.expire(`presence:${playerId}`, 120);
  const friends = await db.any('SELECT CASE WHEN player_a=$1 THEN player_b ELSE player_a END AS fid FROM friendships WHERE player_a=$1 OR player_b=$1', [playerId]);
  for (const f of friends) io.to(`player:${f.fid}`).emit('friend_presence', { playerId, device, status, online: true });
}
export async function recordActivity(playerId: string, eventType: string, eventData: any, visibleToFriends = true) {
  await db.none('INSERT INTO activity_feed(player_id, event_type, event_data, visible_to_friends) VALUES ($1, $2, $3, $4)', [playerId, eventType, JSON.stringify(eventData), visibleToFriends]);
  if (visibleToFriends) {
    const friends = await db.any('SELECT CASE WHEN player_a=$1 THEN player_b ELSE player_a END AS fid FROM friendships WHERE player_a=$1 OR player_b=$1', [playerId]);
    for (const f of friends) io.to(`player:${f.fid}`).emit('friend_activity', { playerId, eventType, eventData });
  }
}
export async function getFriendsList(playerId: string) {
  const friends = await db.any('SELECT CASE WHEN player_a=$1 THEN player_b ELSE player_a END AS fid FROM friendships WHERE player_a=$1 OR player_b=$1', [playerId]);
  const out: any[] = [];
  for (const f of friends) {
    const presence = await redis.hgetall(`presence:${f.fid}`);
    const p = await db.one('SELECT id, name, avatar_url FROM players WHERE id=$1', [f.fid]);
    out.push({ ...p, online: !!presence.online, device: presence.device, status_text: presence.status_text, last_active: presence.last_active });
  }
  return out;
}

