// src/components/FriendsPanel.tsx
import useSWR from 'swr';
import { useEffect, useState } from 'react';
import { useSocket } from '../hooks/useSocket';
export function FriendsPanel({ playerId }: any) {
  const { data: friends, mutate: mutateFriends } = useSWR(`/api/friends/${playerId}`, u => fetch(u).then(r => r.json()));
  const [feed, setFeed] = useState<any[]>([]);
  const socket = useSocket();
  useEffect(() => {
    fetch(`/api/friends/${playerId}/activity`).then(r => r.json()).then(setFeed);
    socket.on('friend_presence', () => mutateFriends());
    socket.on('friend_activity', (e: any) => setFeed(f => [e, ...f].slice(0, 50)));
    return () => { socket.off('friend_presence'); socket.off('friend_activity'); };
  }, [socket]);
  return (
    <div className='grid grid-cols-2 gap-4 p-4 bg-slate-950'>
      <section>
        <h2 className='text-xl font-bold text-white mb-3'>Friends</h2>
        {friends?.map((f: any) => (
          <div key={f.id} className='flex items-center gap-3 p-2 bg-slate-900 rounded mb-1'>
            <div className='relative'>
              <img src={f.avatar_url} className='w-10 h-10 rounded-full' alt='' />
              <div className={`absolute bottom-0 right-0 w-3 h-3 rounded-full border-2 border-slate-900 ${f.online ? 'bg-emerald-400' : 'bg-slate-500'}`} />
            </div>
            <div className='flex-1'>
              <div className='text-white font-bold'>{f.name}</div>
              <div className='text-xs text-slate-400'>{f.online ? `${f.status_text} · ${f.device}` : `offline · ${formatLastActive(f.last_active)}`}</div>
            </div>
          </div>
        ))}
      </section>
      <section>
        <h2 className='text-xl font-bold text-white mb-3'>Activity</h2>
        {feed.map((e: any, i: number) => (
          <div key={i} className='p-2 bg-slate-900 rounded mb-1 text-sm text-slate-300'>
            <span className='text-cyan-400 font-bold'>{e.player_name || 'Friend'}</span> {formatActivity(e.eventType, e.eventData)}
          </div>
        ))}
      </section>
    </div>
  );
}
function formatLastActive(ts: string) { if (!ts) return 'never'; const m = Math.floor((Date.now() - parseInt(ts)) / 60000); if (m < 60) return `${m}m ago`; if (m < 1440) return `${Math.floor(m / 60)}h ago`; return `${Math.floor(m / 1440)}d ago`; }
function formatActivity(type: string, data: any) { switch (type) { case 'achievement_unlocked': return `unlocked ${data.name}`; case 'match_won': return `won a match`; case 'level_up': return `reached level ${data.level}`; default: return type; } }
